code = """import json
import pandas as pd

books_details_path = locals()['var_function-call-2126996606857761453']
with open(books_details_path, 'r') as f:
    books_details = json.load(f)

df_books = pd.DataFrame(books_details)

def extract_year_robust(details):
    import re
    year_patterns = [
        r'(?:on|in) (?:January|February|March|April|May|June|July|August|September|October|November|December) \d{1,2}, (\d{4})',
        r'(?:on|in) (\d{4})',
        r'edition in (\d{4})',
        r'published by [^,]+, (\d{4})'
    ]
    for pattern in year_patterns:
        match = re.search(pattern, details)
        if match:
            return int(match.group(1))
    return None

df_books['publication_year'] = df_books['details'].apply(extract_year_robust)
df_books = df_books.dropna(subset=['publication_year'])
df_books['publication_decade'] = (df_books['publication_year'] // 10 * 10).astype(int)

reviews_path = locals()['var_function-call-2861002454760239851']
with open(reviews_path, 'r') as f:
    reviews_data = json.load(f)
df_reviews = pd.DataFrame(reviews_data)

df_reviews['rating'] = df_reviews['rating'].astype(float)

df_reviews['book_id_from_purchase'] = df_reviews['purchase_id'].str.replace('purchaseid_', 'bookid_')

df_merged = pd.merge(df_books, df_reviews, left_on='book_id', right_on='book_id_from_purchase', how='inner')

book_count_per_decade = df_merged.groupby('publication_decade')['book_id'].nunique().reset_index()
book_count_per_decade.columns = ['publication_decade', 'distinct_book_count']

decades_with_at_least_10_books = book_count_per_decade[book_count_per_decade['distinct_book_count'] >= 10]

if not decades_with_at_least_10_books.empty:
    df_filtered = df_merged[df_merged['publication_decade'].isin(decades_with_at_least_10_books['publication_decade'])]
    average_rating_per_decade = df_filtered.groupby('publication_decade')['rating'].mean().reset_index()
    highest_avg_rating_decade = average_rating_per_decade.loc[average_rating_per_decade['rating'].idxmax()]
    result = highest_avg_rating_decade.to_json()
else:
    result = json.dumps({'error': 'No decades with at least 10 distinct books.', 'book_count_per_decade': book_count_per_decade.to_json(orient='records')})

print('__RESULT__:')
print(result)"""

